SET search_path TO core; CREATE TABLE IF NOT EXISTS expertise_options (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(100) NOT NULL UNIQUE, is_active BOOLEAN NOT NULL DEFAULT TRUE); ALTER TABLE expertise_options ADD COLUMN IF NOT EXISTS is_active BOOLEAN NOT NULL DEFAULT TRUE, ADD COLUMN IF NOT EXISTS deleted BOOLEAN NOT NULL DEFAULT FALSE, ADD COLUMN IF NOT EXISTS created_at TIMESTAMP, ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP; UPDATE expertise_options SET created_at = COALESCE(created_at, now()), updated_at = COALESCE(updated_at, now()) WHERE created_at IS NULL OR updated_at IS NULL;

SET search_path TO core; INSERT INTO expertise_options (name, is_active) VALUES ('Land Surveying', true), ('Architecture', true), ('Legal Advice', true), ('Civil Engineering', true), ('Environmental Assessment', true), ('Urban Planning', true), ('Real Estate Law', true), ('Property Appraisal', true) ON CONFLICT (name) DO NOTHING;
